#include<bits/stdc++.h>
using namespace std;
long long fastpow(long long x,long long y,long long mod)
{
    long long ans=1;
    while(y)
    {
        if(y&1)
        {
            ans=ans*x%mod;
        }
        x=x*x%mod;
        y/=2;
    }
    return ans;
}
int main()
{
    long long t;
    scanf("%lld",&t);
    while(t--)
    {
        long long a,p;
        scanf("%lld%lld",&a,&p);
        if(a<=1||a>=p)
        {
            printf("No\n");
            continue;
        }
        if(fastpow(a,p-1,p)!=1)
        {
            printf("No\n");
            continue;
        }
        bool flag=true;
        for(long long i=1;i*i<=p-1;i++)
        {
            if((p-1)%i!=0)
            {
                continue;
            }
            if(1<=i&&i<p-1&&fastpow(a,i,p)==1)
            {
                flag=false;
                break;
            }
            i=(p-1)/i;
            if(1<=i&&i<p-1&&fastpow(a,i,p)==1)
            {
                flag=false;
                break;
            }
            i=(p-1)/i;
        }
        if(flag)
        {
            printf("Yes\n");
        }
        else
        {
            printf("No\n");
        }
    }
    return 0;
}
